import { TimeField } from '@tale-ui/react/time-field';

export function AppointmentTimeField() {
  return (
    <TimeField.Root>
      <TimeField.Label>Time</TimeField.Label>
      <TimeField.DateInput style={{ display: 'flex' }}>
        {(segment) => <TimeField.Segment segment={segment} />}
      </TimeField.DateInput>
    </TimeField.Root>
  );
}
